<td>设备正常</td>
</tr>
<tr>
<td>错误</td>
<td><code v-pre>puppet.device.status.error</code></td>
<td>设备错误</td>
</tr>
<tr>
<td>降级</td>
<td><code v-pre>puppet.device.status.degraded</code></td>
<td>设备降级</td>
</tr>
<tr>
<td>就绪</td>
<td><code v-pre>puppet.device.status.ready</code></td>
<td>设备就绪</td>
</tr>
<tr>
